def page(dom, slug, t, d, k, style, nav, main):
  slots, canon = S[dom], f'https://www.{dom}/{slug}'
  ld = json.dumps({"@context":"https://schema.org","@type":"WebPage","name":t,"description":d,"url":canon,"breadcrumb":{"@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https://www."+dom+"/"},{"@type":"ListItem","position":2,"name":t,"item":canon}]}})
  return f'''<!DOCTYPE html><html lang=en-GB><head><meta charset=UTF-8><meta name=viewport content="width=device-width,initial-scale=1"><title>{t}</title><meta name=description content="{d}"><meta name=keywords content="{k}"><meta name=robots content="index,follow,max-snippet:-1,max-image-preview:large"><link rel=canonical href="{canon}"><meta property=og:title content="{t}"><meta property=og:description content="{d}"><meta property=og:url content="{canon}"><meta property=og:type content=website><meta property=og:site_name content="{t.split('|')[0].strip()}"><meta property=og:locale content=en_GB><meta name=twitter:card content=summary_large_image><meta name=twitter:title content="{t}"><meta name=twitter:description content="{d}"><meta name=google-adsense-account content={AC}>{ADJS}<script type=application/ld+json>{ld}</script><style>{style}</style></head><body>{nav}{ads(slots[0])}<div class=co>{main}</div>{ads(slots[1]) if len(slots)==3 else ''}{ads(slots[-1])}<footer>(c) 2026 {dom} — <a href=/>Home</a></footer>{SKM}</body></html>'''

def w(dom, pages):
  d = f'/var/www/{D[dom]}/public'
  c = 0
  for slug,t,desc,kw,main in pages:
    with open(f'{d}/{slug}','w') as f:
      f.write(page(dom,slug,t,desc,kw,ST[dom],NV[dom],main))
    c+=1
    print(f'  {slug}')
  print(f'  => {c} pages ({d}/)')

