# toolstack.uk - calculators with interactive JS
def calc(slug, title, desc, keywords, icon, calc_html, calc_js, rates):
  main = f'<div class=hero><h2>{icon} {title}</h2><p>{desc}</p></div><div class=co>'
  main += f'<div class=cd><h2>Try Our {title}</h2><div class=cb>{calc_html}<div class=cr id=r></div></div>'
  main += f'<h2>UK Rates (2026/27)</h2><table><tr><th>Category</th><th>Rate</th></tr>'
  for r in rates: main += f'<tr><td>{r[0]}</td><td>{r[1]}</td></tr>'
  main += '</table></div><div class=cd>'
  main += f'<h2>Why Use Our {title}?</h2><ul><li>Free - no sign-up</li><li>Updated for 2026/27</li><li>Instant results</li><li>Works on all devices</li><li>Privacy-first - runs in browser</li></ul>'
  main += '</div><a href=/ class=bl><- Back to ToolStack</a></div>'
  if calc_js: main += f'<script>{calc_js}</script>'
  return (slug, title, desc, keywords, main)

